import { defineConfig } from "astro/config";
import emdash from "emdash";
import { autobuildPlugin } from "@plugdash/autobuild";

export default defineConfig({
	integrations: [
		emdash({
			plugins: [
				autobuildPlugin({
					hookUrl: import.meta.env.CF_PAGES_DEPLOY_HOOK,
					collections: ["posts"],
					debounceMs: 5000,
				}),
			],
		}),
	],
});
